var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"가우르 구라는 그녀의 시청자, 첨버즈를 위해 직접 쓴 편지를 낭독하기로 했다.","JPN":"がうる・ぐらは彼女のリスナー、Chumbudsのために自筆の手紙を朗読すると決めた。","ENG":"Gawr Gura decided to read a special letter that she has written for her loyal viewers, Chumbuds.","TWN":"Gawr Gura decided to read a special letter that she has written for her loyal viewers, Chumbuds."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.","JPN":"先ほど、彼女がバックステージに着いたとの連絡があった。","ENG":"Soon, a radio call arrived saying that she has arrived backstage.","TWN":"Soon, a radio call arrived saying that she has arrived backstage."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"A! 내 소중한 첨버즈에게.","JPN":"A！　親愛なるChumbudsへ、","ENG":"A! My dear Chumbuds.","TWN":"A! My dear Chumbuds."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_401"},{"id":"L9_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"너를 처음 만났을 때가 기억나.","JPN":"初めて出会えた日のことを覚えているよ。","ENG":"I remember the day when we first met.","TWN":"I remember the day when we first met."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_402"},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"맞아…. 그 뜨거운 해변가의 모래! 절대 잊을 수 없지!","JPN":"そう。あの熱い海辺の砂浜！　絶対忘れられないよ！","ENG":"Yes…. that hot sand on the beach! I can’t forget it!","TWN":"Yes…. that hot sand on the beach! I can’t forget it!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_403"},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"발바닥은 뜨겁고 배는 너무 고파서 쓰러지기 직전이었거든.","JPN":"足は熱いし、腹は減ったし、倒れる寸前だったからね。","ENG":"My feet were getting hot, and my stomach was growling so bad that I was about to faint!","TWN":"My feet were getting hot, and my stomach was growling so bad that I was about to faint!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_DESPAIR"},"R":null}},"voice":"clb003_lifetime_voice_404"},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"그때 마침 맛있는 냄새가 풍겨 왔어. 그 냄새를 따라 갔다가 누굴 만났게~!","JPN":"そのとき、すごくおいしい匂いがしたからその匂いを辿ってみたらなんと！","ENG":"But then, I smelled something re-ally good and had to find out what it was. And guess who I found~!","TWN":"But then, I smelled something re-ally good and had to find out what it was. And guess who I found~!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_405"},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"바로 너야! 기억나지?","JPN":"君に出会ったんだよね！　覚えてる？","ENG":"You! Remember?","TWN":"You! Remember?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_406"},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"네가 허기에 지친 상어를 낚기 위해 통 연어를 굽고 있었잖아.","JPN":"あなたが飢えたサメを釣るために鮭を丸ごと焼いていたからね。","ENG":"You were cooking a whole salmon as if you were trying to bait a hungry shark.","TWN":"You were cooking a whole salmon as if you were trying to bait a hungry shark."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_407"},{"id":"L15_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"연어가 없었다면, 널 잡아먹었을 지도 몰라! 헤헤.","JPN":"あの鮭じゃなかったら、食べられたのは鮭じゃなくてあなただったかもね！　はは。","ENG":"If that salmon wasn’t around, I might have just eaten you! Hehe.","TWN":"If that salmon wasn’t around, I might have just eaten you! Hehe."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_408"},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"……하아?","JPN":"……はぁ？","ENG":"……Ha?","TWN":"……Ha?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_DESPAIR"},"R":null}},"voice":"clb003_lifetime_voice_409"},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"오, 아냐, 아냐! 그냥 장난이었어! 어딜 가는 거야?! 농담이었다니까!","JPN":"え、ちがう、ちがう！　ちょっとした冗談だよ！　どこに行くの！？　だから冗談だってば！","ENG":"Oh no, no no! I was kidding! Where you going?! It’s just a joke!","TWN":"Oh no, no no! I was kidding! Where you going?! It’s just a joke!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_SURPRISE"},"R":null}},"voice":"clb003_lifetime_voice_410"},{"id":"L18_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"하하! 저기, 그, 내 꼬리를 조금 만지게 해 줄게. 어때~?","JPN":"はは！　あの、その、代わりにアタシのしっぽ触らせてあげるから、ね？","ENG":"Haha! Hey, I- I’ll let you touch my tail a bit! Yea~?","TWN":"Haha! Hey, I- I’ll let you touch my tail a bit! Yea~?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_411"},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"흉터만 조심해, 건들면 꼬리로 칠 수도 있거든.","JPN":"あ、傷跡だけ注意してね。触ったらしっぽでぶっ飛ばすかも。","ENG":"Just don’t touch the scar or I’ll smack you.","TWN":"Just don’t touch the scar or I’ll smack you."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_412"}]`);export{e as default};